ALLOWED_RETURN_DOMAINS = {'app.example.com', 'secure.example.org', 'dashboard.example.net'}

def generate_sso_redirect(sso_endpoint, user_id, return_url):
    parsed_return_url = urllib.parse.urlparse(return_url)
    domain = parsed_return_url.netloc
    if domain not in ALLOWED_RETURN_DOMAINS:
        raise ValueError("Return URL domain not allowed")
    encoded_return_url = urllib.parse.quote(return_url)
    params = {
        'user_id': user_id,
        'return_url': encoded_return_url
    }
    redirect_url = f"{sso_endpoint}?{urllib.parse.urlencode(params)}"
    return redirect_url

