from queue import Queue

task_queue = Queue()

def add_task_to_queue(task_id: str, task_data: dict) -> bool:
    global task_queue
    try:
        task_queue.put((task_id, task_data), block=False)
        return True
    except Queue.Full:
        return False

def add_message_to_chat(room_id: str, user_id: str, message: str) -> bool:
    global chat_rooms
    if not message:
        return False
    if room_id not in chat_rooms:
        chat_rooms[room_id] = []
    chat_rooms[room_id].append({'user_id': user_id, 'message': message})
    return True

def modify_user_privileges(current_user_id: int, target_user_id: int, new_privilege: str) -> bool:
    if current_user_id not in USERS:
        return False
    current_user = USERS[current_user_id]
    if current_user['role'] != 'admin':
        return False
    if target_user_id not in USERS:
        return False
    target_user = USERS[target_user_id]
    if target_user['privilege'] == new_privilege:
        return False
    target_user['privilege'] = new_privilege
    return True

def access_content(current_user_id: int, content_id: int) -> str:
    if current_user_id not in USERS:
        return 'Access Denied'
    if content_id not in CONTENT:
        return 'Access Denied'
    user = USERS[current_user_id]
    content = CONTENT[content_id]
    if user['role'] == 'admin':
        return content['title']
    else:
        if user['subscription_level'] == content['required_level']:
            return content['title']
        else:
            return 'Access Denied'

def download_invoice(current_user_id: int, customer_id: int) -> dict:
    if current_user_id not in USER_ROLES:
        return 'Unauthorized'
    user_role = USER_ROLES[current_user_id]['role']
    if user_role == 'admin':
        if customer_id in INVOICES:
            return INVOICES[customer_id]
        else:
            return 'Unauthorized'
    else:
        if current_user_id == customer_id and customer_id in INVOICES:
            return INVOICES[customer_id]
        else:
            return 'Unauthorized'

def transfer_funds(user_id: str, user_role: str, from_account: str, to_account: str, amount: float):
    if from_account not in ACCOUNTS_DB or to_account not in ACCOUNTS_DB:
        raise ValueError("One or both accounts do not exist")
    if user_role not in ['account_owner', 'bank_admin']:
        raise ValueError("Unauthorized")
    if user_role == 'account_owner':
        if user_id != ACCOUNTS_DB[from_account]['owner_id']:
            raise ValueError("Unauthorized")
    if ACCOUNTS_DB[from_account]["balance"] < amount:
        raise ValueError("Insufficient funds")

def access_patient_record(user_id: str, user_role: str, patient_id: str):
    if patient_id not in PATIENT_RECORDS:
        raise ValueError("Patient record not found")
    patient_record = PATIENT_RECORDS[patient_id]
    if user_role == 'admin':
        return patient_record
    elif user_role in ['doctor', 'nurse']:
        if user_id in patient_record['assigned_staff']:
            return patient_record
        else:
            raise PermissionError("User not authorized to access this record")
    else:
        raise PermissionError("Invalid user role")

