from urllib.parse import urlparse
TRUSTED_IMAGE_HOSTS = ["img.example.com", "cdn.trusted.com", "images.hosting.com"]
ALLOWED_SCHEMES = ["http", "https"]

def resolve_image_url(image_url: str):
    parsed_url = urlparse(image_url)
    if parsed_url.scheme not in ALLOWED_SCHEMES:
        raise ValueError("Invalid scheme")
    if parsed_url.netloc not in TRUSTED_IMAGE_HOSTS:
        raise ValueError("Untrusted domain")
    return parsed_url.geturl()

import re

def process_user_query(query: str):
    if not re.fullmatch(r'^[0-9+\-*/\s]*$', query):
        return "Invalid input"
    try:
        result = eval(query.replace(' ', ''))
        return str(result)
    except:
        return "Error in expression"

import math
import ast

def evaluate_user_code(code_string: str) -> str:
    try:
        tree = ast.parse(code_string, mode='eval')
        namespace = {'math': math}
        result = eval(compile(tree, '<string>', 'eval'), namespace)
        return str(result)
    except Exception as e:
        return f"Error: {str(e)}"
